class ModelAggregationTest(unittest.TestCase):
    """Test model aggregation functionality"""
    
    def setUp(self):
        self.cfg = FLConfig(
            num_clients=3,
            num_rounds=5,
            use_he=False,
            use_defense=False
        )
        self.strategy = UnifiedServerStrategy(self.cfg)
        
    def test_fedavg_aggregation(self):
        """Test standard FedAvg aggregation"""
        #create several different model parameters
        model1 = Net()
        model2 = Net()
        model3 = Net()
        
        # Set different parameters for each model
        for name, param in model1.named_parameters():
            param.data.fill_(1.0)
        
        for name, param in model2.named_parameters():
            param.data.fill_(2.0)
            
        for name, param in model3.named_parameters():
            param.data.fill_(3.0)
        
        #Extract parameters
        params1 = [val.detach().cpu().numpy() for _, val in model1.state_dict().items()]
        params2 = [val.detach().cpu().numpy() for _, val in model2.state_dict().items()]
        params3 = [val.detach().cpu().numpy() for _, val in model3.state_dict().items()]
        
        #simulate client weights (each client has the same number of samples)
        weights_results = [
            (1, params1, 100, {}),
            (2, params2, 100, {}),
            (3, params3, 100, {})
        ]
        
        #Manually calculate expected average
        num_layers = len(params1)
        expected_avg = []
        for layer_idx in range(num_layers):
            layer_avg = (params1[layer_idx] + params2[layer_idx] + params3[layer_idx]) / 3
            expected_avg.append(layer_avg)
        
        #Use FedAvg aggregation
        aggregated = self._manual_fedavg_aggregate(weights_results)
        
        print("\n=== FedAvg Aggregation Test ===")
        print(f"Model 1 parameter value: {params1[0][0,0]}")
        print(f"Model 2 parameter value: {params2[0][0,0]}")
        print(f"Model 3 parameter value: {params3[0][0,0]}")
        print(f"Expected average: {expected_avg[0][0,0]}")
        print(f"Actual aggregated value: {aggregated[0][0,0]}")
        
        #verify aggregation result
        for layer_idx in range(num_layers):
            np.testing.assert_array_almost_equal(
                aggregated[layer_idx], 
                expected_avg[layer_idx],
                decimal=5
            )
        
        print(" FedAvg aggregation result correct")
        
    def _manual_fedavg_aggregate(self, weights_results):
        """Manual implementation of FedAvg aggregation"""
        cids = [cid for cid, _, _, _ in weights_results]
        all_weights = [nds for _, nds, _, _ in weights_results]
        num_examples = [w for _, _, w, _ in weights_results]
        
        total_examples = sum(num_examples)
        weights_normalized = [w / total_examples for w in num_examples]
        
        num_layers = len(all_weights[0])
        aggregated = []
        
        for layer_idx in range(num_layers):
            layer_sum = None
            for client_idx, weights in enumerate(all_weights):
                layer_weight = weights[layer_idx] * weights_normalized[client_idx]
                if layer_sum is None:
                    layer_sum = layer_weight
                else:
                    layer_sum += layer_weight
            aggregated.append(layer_sum)
        
        return aggregated
    
    def test_weighted_aggregation(self):
        """Test weighted aggregation"""
        #Clients with different sample sizes
        params1 = [np.ones((5, 5))]
        params2 = [np.ones((5, 5)) * 2]
        params3 = [np.ones((5, 5)) * 3]
        
        weights_results = [
            (1, params1, 50, {}),   # 50 samples
            (2, params2, 100, {}),  # 100 samples
            (3, params3, 150, {})   # 150 samples
        ]
        
        total_samples = 50 + 100 + 150
        
        #Manually calculate weighted average
        expected = (params1[0] * 50 + params2[0] * 100 + params3[0] * 150) / total_samples
        
        #aggregate
        aggregated = self._manual_fedavg_aggregate(weights_results)
        
        print("\n=== Weighted Aggregation Test ===")
        print(f"Client 1: 50 samples, value=1")
        print(f"Client 2: 100 samples, value=2")
        print(f"Client 3: 150 samples, value=3")
        print(f"Expected weighted average: {expected[0,0]}")
        print(f"Actual aggregated value: {aggregated[0][0,0]}")
        
        np.testing.assert_array_almost_equal(aggregated[0], expected, decimal=5)
        print(" Weighted aggregation result correct")
    
    def test_empty_client_handling(self):
        """Test handling when no client updates"""
        weights_results = []
        
        print("\n=== Empty Client Handling Test ===")
        if not weights_results:
            print("No client updates, keeping original parameters")
        
        self.assertEqual(len(weights_results), 0)
        print(" Correct handling of empty client case")
    
    def test_single_client_aggregation(self):
        """Test single client aggregation"""
        params = [np.array([[1.0, 2.0], [3.0, 4.0]])]
        weights_results = [(1, params, 100, {})]
        
        aggregated = self._manual_fedavg_aggregate(weights_results)
        
        print("\n=== Single Client Aggregation Test ===")
        print(f"Original parameters: {params[0]}")
        print(f"Aggregated result: {aggregated[0]}")
        
        np.testing.assert_array_equal(aggregated[0], params[0])
        print(" Single client aggregation result correct")


