class DefenseAggregationTest(unittest.TestCase):
    """Test defensive aggregation (MAD + Reputation)"""
    
    def setUp(self):
        self.cfg = FLConfig(
            num_clients=3,
            use_defense=True,
            defense_sigma=2.0,
            trust_ema_alpha=0.7
        )
        self.client_trusts = {1: 1.0, 2: 1.0, 3: 1.0}
        self.client_trust_history = {1: [], 2: [], 3: []}
        
    def test_mad_reputation_aggregation(self):
        """Test MAD+Reputation aggregation"""
        #create clients with different parameters
        params1 = [np.ones((3, 3))]      # Normal
        params2 = [np.ones((3, 3)) * 2]  # Normal
        params3 = [np.ones((3, 3)) * 10] # Anomaly
        
        weights_results = [
            (1, params1, 100, False),
            (2, params2, 100, False),
            (3, params3, 100, False)
        ]
        
        #use defensive aggregation
        aggregated = aggregate_with_mad_reputation(
            self.cfg,
            weights_results,
            self.client_trusts,
            self.client_trust_history
        )
        
        print("\n=== MAD+Reputation Aggregation Test ===")
        print(f"Client 1 parameter value: {params1[0][0,0]}")
        print(f"Client 2 parameter value: {params2[0][0,0]}")
        print(f"Client 3 parameter value: {params3[0][0,0]} (anomaly)")
        print(f"Defensive aggregation result: {aggregated[0][0,0]}")
        
        #Defensive aggregation should reduce the impact of anomalies
        #Result should be closer to normal average than full average
        normal_avg = (1 + 2) / 2
        full_avg = (1 + 2 + 10) / 3
        
        self.assertLess(abs(aggregated[0][0,0] - normal_avg), 
                        abs(aggregated[0][0,0] - full_avg))
        
        print(f"Normal average: {normal_avg}")
        print(f"Full average: {full_avg}")
        print(" Defensive aggregation effectively reduces impact of anomalies")
        
    def test_trust_update(self):
        """Test trust update"""
        #simulate trust update after one round of aggregation
        round_scores = {1: 0.95, 2: 0.93, 3: 0.45}
        alpha = self.cfg.trust_ema_alpha
        
        updated_trusts = {}
        for cid in [1, 2, 3]:
            old_trust = self.client_trusts.get(cid, 1.0)
            new_trust = alpha * old_trust + (1 - alpha) * round_scores[cid]
            updated_trusts[cid] = new_trust
        
        print("\n=== Trust Update Test ===")
        print(f"Client 3 trust: {self.client_trusts[3]:.4f} → {updated_trusts[3]:.4f}")
        self.assertLess(updated_trusts[3], self.client_trusts[3])
        print(" Anomalous client's trust is reduced")


